sql:
SELECT bill_id, bill_date, total_charge
FROM bills
WHERE bill_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT total_charge, payment_status
FROM bills
ORDER BY total_charge DESC;

SELECT COUNT(*)
FROM calls
WHERE customer_id = 1234 AND strftime('%Y-%m', call_start_time) = '2023-04';

SELECT SUM(total_charge) AS total_paid_bills
FROM bills
WHERE payment_status = 'paid';

SELECT SUM(charge) AS total_charges
FROM calls
WHERE customer_id = 1 AND call_direction = 'incoming' AND call_start_time BETWEEN '2023-01-01 00:00:00' AND '2023-01-31 23:59:59';

external_knowledge:
- 'storm they create' is a metaphor for the total charge a customer incurs; 
- 'chosen stormmaker' refers to the specific customer with a given `customer_id` (0 in this case); 
- 'position in this ranking whirlwind' indicates the rank of the customer based on their total charge among all customers.

- 'start of the year' refers to '2023-01-01 00:00:00';
- 'English-speaking customers' means customers whose `preferred_language` is 'English';
- 'made a call' indicates records where a `call_start_time` exists.
